import java.util.Scanner;

public class BufferOverflowExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Create a fixed-size array with a capacity of 10 characters
        char[] buffer = new char[10];

        // Copy the user input into the fixed-size array with bounds checking
        int length = Math.min(name.length(), buffer.length);
        for (int i = 0; i < length; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Welcome, " + new String(buffer, 0, length));
    }
}

### Explanation:
